@@ -0,0 +1,215 @@
+:root {
+  color-scheme: light dark;
+  --bg: #0b0d10;
+  --panel: #11151b;
+  --text: #e7ecf3;
+  --muted: #a3adbb;
+  --line: rgba(255, 255, 255, 0.1);
+  --accent: #7bdcff;
+  --accent2: #a78bfa;
+  --shadow: rgba(0, 0, 0, 0.35);
+  --radius: 16px;
+}
+
+@media (prefers-color-scheme: light) {
+  :root {
+    --bg: #f7f8fb;
+    --panel: #ffffff;
+    --text: #0b0d10;
+    --muted: #4d5a6a;
+    --line: rgba(0, 0, 0, 0.08);
+    --shadow: rgba(0, 0, 0, 0.08);
+  }
+}
+
+* {
+  box-sizing: border-box;
+}
+
+html,
+body {
+  height: 100%;
+}
+
+body {
+  margin: 0;
+  font: 16px/1.55 ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
+  color: var(--text);
+  background:
+    radial-gradient(1200px 900px at 15% 10%, rgba(123, 220, 255, 0.2), transparent 55%),
+    radial-gradient(1100px 900px at 85% 20%, rgba(167, 139, 250, 0.18), transparent 55%),
+    radial-gradient(900px 700px at 45% 90%, rgba(123, 220, 255, 0.08), transparent 60%),
+    var(--bg);
+}
+
+a {
+  color: inherit;
+  text-decoration: none;
+}
+
+a:hover {
+  text-decoration: underline;
+}
+
+code {
+  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", monospace;
+  font-size: 0.95em;
+}
+
+.wrap {
+  max-width: 980px;
+  margin: 0 auto;
+  padding: 40px 22px 28px;
+}
+
+.top {
+  display: flex;
+  align-items: center;
+  justify-content: space-between;
+  gap: 18px;
+  margin-bottom: 26px;
+}
+
+.brand {
+  display: flex;
+  align-items: center;
+  gap: 14px;
+  min-width: 240px;
+}
+
+.mark {
+  width: 44px;
+  height: 44px;
+  border-radius: 12px;
+  display: grid;
+  place-items: center;
+  background: linear-gradient(135deg, rgba(123, 220, 255, 0.22), rgba(167, 139, 250, 0.22));
+  border: 1px solid var(--line);
+  box-shadow: 0 10px 30px var(--shadow);
+  letter-spacing: 0.6px;
+  font-weight: 700;
+}
+
+.name h1 {
+  margin: 0;
+  font-size: 20px;
+  letter-spacing: 0.2px;
+}
+
+.name p {
+  margin: 2px 0 0;
+  color: var(--muted);
+  font-size: 13.5px;
+}
+
+.links {
+  display: flex;
+  gap: 10px;
+}
+
+.btn {
+  padding: 10px 12px;
+  border-radius: 12px;
+  border: 1px solid var(--line);
+  background: rgba(255, 255, 255, 0.02);
+  box-shadow: 0 10px 30px var(--shadow);
+}
+
+.btn.primary {
+  border-color: transparent;
+  background: linear-gradient(135deg, rgba(123, 220, 255, 0.55), rgba(167, 139, 250, 0.55));
+}
+
+.hero {
+  display: grid;
+  grid-template-columns: 1.05fr 0.95fr;
+  gap: 26px;
+  align-items: center;
+  padding: 18px;
+  border: 1px solid var(--line);
+  border-radius: var(--radius);
+  background: color-mix(in srgb, var(--panel) 88%, transparent);
+  box-shadow: 0 18px 60px var(--shadow);
+}
+
+.copy h2 {
+  margin: 0 0 8px;
+  font-size: 28px;
+  letter-spacing: -0.2px;
+}
+
+.copy p {
+  margin: 0 0 10px;
+  color: var(--muted);
+}
+
+.copy .note {
+  color: var(--text);
+  font-weight: 600;
+}
+
+.shot {
+  margin: 0;
+}
+
+.shot img {
+  width: 100%;
+  height: auto;
+  border-radius: 14px;
+  border: 1px solid var(--line);
+  box-shadow: 0 18px 60px var(--shadow);
+  background: color-mix(in srgb, var(--panel) 95%, transparent);
+}
+
+.details {
+  display: grid;
+  grid-template-columns: repeat(3, 1fr);
+  gap: 14px;
+  margin-top: 14px;
+}
+
+.card {
+  border: 1px solid var(--line);
+  border-radius: var(--radius);
+  padding: 14px 14px 12px;
+  background: color-mix(in srgb, var(--panel) 92%, transparent);
+  box-shadow: 0 14px 40px var(--shadow);
+}
+
+.card h3 {
+  margin: 0 0 6px;
+  font-size: 14px;
+  letter-spacing: 0.2px;
+}
+
+.card p {
+  margin: 0;
+  color: var(--muted);
+  font-size: 13.5px;
+}
+
+.foot {
+  margin-top: 22px;
+  text-align: center;
+  color: var(--muted);
+  font-size: 13px;
+}
+
+.foot a {
+  text-decoration: underline;
+  text-decoration-color: color-mix(in srgb, var(--muted) 45%, transparent);
+}
+
+@media (max-width: 860px) {
+  .top {
+    flex-direction: column;
+    align-items: flex-start;
+  }
+  .hero {
+    grid-template-columns: 1fr;
+  }
+  .details {
+    grid-template-columns: 1fr;
+  }
+}
+
